private struct WazeTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum WazeScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("service") || t.contains("contribute"):
            WazeMapScreen()
        case let t where t.contains("activ") || t.contains("clock"):
            WazeActivityScreen()
        default:
            WazeGenericListScreen(title: tab)
        }
    }
}
